async (params, browser) => {
  // Search Canva elements
  await browser.open(`https://www.canva.com/search/${params.element_type}?q=${params.query}`)

  // Wait for results
  await browser.waitForSelector('img, [role=\'list\'], [role=\'listitem\'], main a', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract element results
  const search_results = await browser.evaluate(`const results = []; const seen = new Set(); const allLinks = document.querySelectorAll('main a[href], [role="list"] a[href]'); for (let i = 0; i < allLinks.length && results.length < 15; i++) { const el = allLinks[i]; const href = el.href || ''; if (!href || seen.has(href) || href === window.location.href) continue; seen.add(href); const imgEl = el.querySelector('img'); if (!imgEl) continue; const ariaLabel = el.getAttribute('aria-label') || ''; const alt = imgEl.getAttribute('alt') || ''; const proEl = el.querySelector('[aria-label*="Pro"], [aria-label*="premium"]'); results.push({ title: ariaLabel || alt, is_premium: !!proEl, image: imgEl.getAttribute('src') || '', url: href }); } const params = new URLSearchParams(window.location.search); return { query: params.get('q') || params.query, element_type: window.location.pathname.split('/search/')[1] || params.element_type, result_count: results.length, results: results }`)

  return search_results
}
